"""
Step ID: step04
Step Name: Compute Effect Size (Cohen's d)
RQ: ch6/6.9.1 - Direct Confidence-Accuracy Trajectory Comparison
Generated: 2026-01-16

PURPOSE:
Compute Cohen's d for paired samples: d = mean(difference) / SD(difference).
This quantifies the magnitude of the difference between confidence and accuracy
decline rates. Uses Cohen (1988) conventions for interpretation.

EXPECTED INPUTS:
  - results/ch6/6.9.1/data/step02_individual_decline_rates.csv
    Columns: ['UID', 'acc_rate', 'conf_rate', 'difference', 'ratio', 'delta_hours', 'SD_decline_acc', 'SD_decline_conf', 'no_decline_flag']
    Format: 100 rows (one per participant)
    Expected rows: 100

EXPECTED OUTPUTS:
  - results/ch6/6.9.1/data/step04_effect_size.csv
    Columns: ['cohen_d', 'interpretation']
    Format: 1 row (single effect size)
    Expected rows: 1

VALIDATION CRITERIA:
  - rows: 1
  - columns: 2
  - no_nan: ['cohen_d']
  - interpretation in ['negligible', 'small', 'medium', 'large']

g_code REASONING:
- Approach: Custom calculation using numpy (d = mean / SD)
- Why: Cohen's d quantifies effect magnitude independent of sample size
- Data flow: Load difference column → compute mean/SD → apply thresholds
- Expected performance: ~2 minutes

IMPLEMENTATION NOTES:
- Analysis tool: numpy.mean, numpy.std (stdlib)
- Validation tool: Inline conditional checks
- Parameters: Cohen (1988) thresholds (0.2, 0.5, 0.8)
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
from typing import Dict, List, Tuple, Any
import traceback

# Add project root to path for imports
PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]  # results/ch6/6.9.1
LOG_FILE = RQ_DIR / "logs" / "step04_effect_size.log"

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
    print(msg)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 4: Compute Effect Size (Cohen's d)")

        # =========================================================================
        # STEP 1: Load Input Data
        # =========================================================================
        # Expected: Individual decline rates (100 rows)
        # Purpose: Extract difference column for effect size calculation

        log("[LOAD] Loading input data...")

        # Load individual decline rates
        df_rates = pd.read_csv(RQ_DIR / "data" / "step02_individual_decline_rates.csv", encoding='utf-8')
        log(f"[LOADED] step02_individual_decline_rates.csv ({len(df_rates)} rows, {len(df_rates.columns)} cols)")

        # =========================================================================
        # STEP 2: Compute Cohen's d (Paired Samples)
        # =========================================================================
        # Tool: numpy.mean, numpy.std
        # What it does: Effect size for paired differences
        # Expected output: Cohen's d value

        log("[ANALYSIS] Computing Cohen's d for paired samples...")

        # Extract difference array
        difference = df_rates['difference'].values

        # Compute Cohen's d
        # Formula: d = mean(difference) / SD(difference)
        # Note: Uses SD of differences (paired design), not pooled SD (independent design)
        mean_difference = np.mean(difference)
        sd_difference = np.std(difference, ddof=1)
        cohen_d = mean_difference / sd_difference

        log(f"[RESULT] Mean difference: {mean_difference:.6f}")
        log(f"[RESULT] SD difference: {sd_difference:.6f}")
        log(f"[RESULT] Cohen's d: {cohen_d:.4f}")

        # =========================================================================
        # STEP 3: Interpret Magnitude
        # =========================================================================
        # Tool: Conditional logic based on Cohen (1988) conventions
        # What it does: Classify effect size as negligible/small/medium/large
        # Expected output: Interpretation string

        log("[INTERPRETATION] Applying Cohen (1988) conventions...")

        # Cohen (1988) thresholds
        abs_d = abs(cohen_d)

        if abs_d < 0.2:
            interpretation = 'negligible'
        elif abs_d < 0.5:
            interpretation = 'small'
        elif abs_d < 0.8:
            interpretation = 'medium'
        else:
            interpretation = 'large'

        log(f"[INTERPRETATION] |d| = {abs_d:.4f} -> {interpretation}")

        # =========================================================================
        # STEP 4: Hypothesis Decision Integration
        # =========================================================================
        # Note: Full decision made in rq_results (combines all evidence)
        # This step just notes the criteria

        log("[NOTE] Hedging hypothesis SUPPORTED if:")
        log("[NOTE]   (1) p_uncorrected < 0.05 (Step 3)")
        log("[NOTE]   AND (2) |cohen_d| > 0.3 (medium+ effect)")
        log("[NOTE] Full decision made in rq_results agent")

        # =========================================================================
        # STEP 5: Save Analysis Outputs
        # =========================================================================
        # These outputs will be used by: rq_results (hypothesis decision)

        log("[SAVE] Saving analysis outputs...")

        # Create results DataFrame
        results = {
            'cohen_d': [cohen_d],
            'interpretation': [interpretation]
        }
        df_results = pd.DataFrame(results)

        # Save effect size
        output_path = RQ_DIR / "data" / "step04_effect_size.csv"
        df_results.to_csv(output_path, index=False, encoding='utf-8')
        log(f"[SAVED] {output_path.name} ({len(df_results)} rows, {len(df_results.columns)} cols)")

        # =========================================================================
        # STEP 6: Validation
        # =========================================================================
        # Validates: Output structure, value ranges, interpretation match

        log("[VALIDATION] Running inline validation...")

        # Check rows
        if len(df_results) != 1:
            log(f"[ERROR] Expected 1 row, got {len(df_results)}")

        # Check columns
        if len(df_results.columns) != 2:
            log(f"[ERROR] Expected 2 columns, got {len(df_results.columns)}")

        # Check for NaN in cohen_d
        if pd.isna(df_results['cohen_d'].values[0]):
            log(f"[ERROR] cohen_d is NaN")

        # Check interpretation is valid
        valid_interpretations = ['negligible', 'small', 'medium', 'large']
        if interpretation not in valid_interpretations:
            log(f"[ERROR] Invalid interpretation: {interpretation}")

        # Check interpretation matches magnitude
        if abs_d < 0.2 and interpretation != 'negligible':
            log(f"[ERROR] |d| < 0.2 but interpretation is {interpretation} (expected negligible)")
        elif 0.2 <= abs_d < 0.5 and interpretation != 'small':
            log(f"[ERROR] 0.2 <= |d| < 0.5 but interpretation is {interpretation} (expected small)")
        elif 0.5 <= abs_d < 0.8 and interpretation != 'medium':
            log(f"[ERROR] 0.5 <= |d| < 0.8 but interpretation is {interpretation} (expected medium)")
        elif abs_d >= 0.8 and interpretation != 'large':
            log(f"[ERROR] |d| >= 0.8 but interpretation is {interpretation} (expected large)")

        # Value range
        if not (-5 <= cohen_d <= 5):
            log(f"[WARNING] Cohen's d outside expected range: {cohen_d}")

        log(f"[VALIDATION] Cohen's d = {cohen_d:.4f}")
        log(f"[VALIDATION] interpretation: {interpretation}")

        log("[SUCCESS] Step 4 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
